import { defineStore } from 'pinia'
import { ref, computed, watch } from 'vue'
import { setI18nLocale, type AppLocale } from '@/locales'
import vi from '@/locales/vi'
import ja from '@/locales/ja'
import en from '@/locales/en'

/**
 * ============================================================
 *  useI18nStore
 *  ------------------------------------------------------------
 *  Pinia store quản lý chuyển ngữ Việt ↔ Nhật cho toàn project.
 *
 *  • Lưu locale vào localStorage để giữ qua các lần reload.
 *  • Tự động phát hiện ngôn ngữ trình duyệt lần đầu.
 *  • Đồng bộ locale với vue-i18n để các component dùng `t()`.
 *  • Cung cấp:
 *      - locale, isVi, isJa (state/getters)
 *      - availableLocales, languageMeta (meta)
 *      - setLocale, toggleLocale, t (actions)
 *      - onChange callback cho mọi component muốn lắng nghe
 * ============================================================
 */

const STORAGE_KEY = 'ngu-cat.locale'
const SUPPORTED: AppLocale[] = ['vi', 'ja', 'en']

export interface LanguageMeta {
  code: AppLocale
  label: string
  nativeLabel: string
  flag: string
}

export const LANGUAGE_META: Record<AppLocale, LanguageMeta> = {
  vi: { code: 'vi', label: 'Vietnamese',  nativeLabel: 'Tiếng Việt',  flag: '🇻🇳' },
  ja: { code: 'ja', label: 'Japanese',    nativeLabel: '日本語',       flag: '🇯🇵' },
  en: { code: 'en', label: 'English',     nativeLabel: 'English',     flag: '🇬🇧' },
}

/* ---------- Helpers ---------- */
function detectInitialLocale(): AppLocale {
  if (typeof window === 'undefined') return 'vi'
  const stored = window.localStorage.getItem(STORAGE_KEY) as AppLocale | null
  if (stored && SUPPORTED.includes(stored)) return stored
  const browser = window.navigator?.language?.toLowerCase() ?? 'vi'
  if (browser.startsWith('ja')) return 'ja'
  return 'vi'
}

function applyDocumentLang(locale: AppLocale) {
  if (typeof document === 'undefined') return
  document.documentElement.setAttribute('lang', locale)
  document.documentElement.setAttribute('data-locale', locale)
}

function persistLocale(locale: AppLocale) {
  if (typeof window === 'undefined') return
  window.localStorage.setItem(STORAGE_KEY, locale)
}

/* ---------- Store factory ---------- */
export const useI18nStore = defineStore('i18n', () => {
  /* ===== state ===== */
  const locale = ref<AppLocale>(detectInitialLocale())
  const isSwitching = ref(false)

  /* ===== getters ===== */
  const isVi = computed(() => locale.value === 'vi')
  const isJa = computed(() => locale.value === 'ja')
  const isEn = computed(() => locale.value === 'en')

  const availableLocales = computed<AppLocale[]>(() => [...SUPPORTED])

  const currentMeta = computed<LanguageMeta>(
    () => LANGUAGE_META[locale.value] ?? LANGUAGE_META.vi,
  )

  const messages = computed(() => ({
    vi,
    ja,
    en,
  }))

  /* ===== actions ===== */
  function setLocale(next: AppLocale) {
    if (!SUPPORTED.includes(next)) return
    if (next === locale.value) return
    isSwitching.value = true
    locale.value = next
    // Đồng bộ với vue-i18n ngay lập tức
    setI18nLocale(next)
    applyDocumentLang(next)
    persistLocale(next)
    // Tắt cờ switching sau 1 frame để component kịp render transition
    if (typeof window !== 'undefined') {
      window.requestAnimationFrame(() => {
        isSwitching.value = false
      })
    }
  }

  function toggleLocale() {
    const next = locale.value === 'vi' ? 'en' : locale.value === 'en' ? 'ja' : 'vi'
    setLocale(next)
  }

  /**
   * Hàm dịch trực tiếp từ store — tiện cho component không dùng `useI18n()`.
   * Hỗ trợ dot-path:  t('nav.timeline')  ->  "Lịch đặt bàn"
   * Hỗ trợ interpolation:  t('greet', { name: 'Per' })
   */
  function t(key: string, params?: Record<string, unknown>): string {
    const lookup = (l: AppLocale): unknown => {
      const localeObj = l === 'vi' ? vi : l === 'ja' ? ja : en
      if (localeObj && typeof localeObj === 'object' && key in localeObj) {
        return (localeObj as Record<string, unknown>)[key]
      }
      return key.split('.').reduce<unknown>(
        (acc, segment) =>
          acc && typeof acc === 'object'
            ? (acc as Record<string, unknown>)[segment]
            : undefined,
        localeObj,
      )
    }
    const raw: unknown = lookup(locale.value) ?? lookup('vi') ?? key
    if (typeof raw !== 'string') return key
    if (!params) return raw
    return Object.entries(params).reduce(
      (acc, [k, v]) => acc.replace(new RegExp(`\\{${k}\\}`, 'g'), String(v)),
      raw,
    )
  }

  /* ===== init ===== */
  // Đồng bộ vue-i18n + <html lang> với giá trị ban đầu.
  setI18nLocale(locale.value)
  applyDocumentLang(locale.value)

  // Watcher: nếu locale thay đổi từ bên ngoài (VD: devtools), vẫn giữ sync.
  watch(locale, (next) => {
    setI18nLocale(next)
    applyDocumentLang(next)
    persistLocale(next)
  })

  return {
    /* state */
    locale,
    isSwitching,
    /* getters */
    isVi,
    isJa,
    isEn,
    availableLocales,
    currentMeta,
    messages,
    /* actions */
    setLocale,
    toggleLocale,
    t,
  }
})

export type I18nStore = ReturnType<typeof useI18nStore>

import { useLanguageStore } from '@/stores/useLanguageStore'
import { useI18nStore } from '@/stores/i18n'
import { i18n } from '@/locales'

// Tầng 1: Flat Key (Không lồng nhau)
function resolveFlatKey(key: string, lang: string): string | undefined {
  const globalMessages = (i18n.global.messages as any).value || i18n.global.messages;
  return globalMessages?.[lang]?.[key] || globalMessages?.['vi']?.[key];
}

// Tầng 2: Nested Key (Vue I18n Standard)
function resolveNestedKey(key: string): string | undefined {
  try {
    const hasKey = i18n.global.te(key);
    if (hasKey) {
      return i18n.global.t(key) as string;
    }
  } catch {
    // ignore
  }
  return undefined;
}

// Tầng 3: Fallback Dictionary
function resolveFromDict(key: string, lang: string): string | undefined {
  const store = useLanguageStore()
  // Try state.lang or vi fallback from dict
  return store.dict?.[lang]?.[key] || store.dict?.[key];
}

export function setApplicationLanguage(lang: 'vi' | 'en' | 'ja') {
  const store = useLanguageStore()
  store.setLanguage(lang)

  const i18nStore = useI18nStore()
  i18nStore.setLocale(lang)

  // Update HTML lang attribute
  if (typeof document !== 'undefined') {
    document.documentElement.lang = lang
    document.documentElement.setAttribute('data-locale', lang)
  }

  console.log(`[i18n] Language changed to: ${lang}`)
}

export function t(key: string, params?: Record<string, any>): string {
  const store = useLanguageStore()
  const lang = store.lang || 'vi'

  // Multi-tier resolution
  let translation = 
    resolveFlatKey(key, lang) ||
    resolveNestedKey(key) ||
    resolveFromDict(key, lang) ||
    key // Fallback to key

  // Apply params if any
  if (params && typeof translation === 'string') {
    translation = Object.entries(params).reduce((result, [paramKey, value]) => {
      return result.replace(`{${paramKey}}`, String(value));
    }, translation);
  }

  return translation;
}

